uint64
sys_lseek(void)
{
  int fd, off, whence;
  if(argint(0, &fd) < 0)
    return -1;
  if(argint(0, &off) < 0)
    return -1;
  if(argint(0, &whence) < 0)
    return -1;

  return lseek(fd, off, whence);
}

uint64
sys_wait(void)
{
  uint64 p;
  int f;
  if(argaddr(0, &p) < 0)
    return -1;
  f = wait(p);
  return f;
}

uint64
sys_sbrk(void)
{
  int addr;
  int n;

  if(argint(0, &n) < 0)
    return -1;
  addr = myproc()->sz;
  if(growproc(n) < 0)
    return -1;
  return addr;
}

uint64
sys_sleep(void)
{
  int n;
  uint ticks0;

  if(argint(0, &n) < 0)
    return -1;
  acquire(&tickslock);
  ticks0 = ticks;
  while(ticks - ticks0 < n){
    if(myproc()->killed){
      release(&tickslock);
      return -1;
    }
    sleep(&ticks, &tickslock);
  }
  release(&tickslock);
  return 0;
}

uint64
sys_kill(void)
{
  int pid;

  if(argint(0, &pid) < 0)
    return -1;
  return kill(pid);
}

// return how many clock tick interrupts have occurred
// since start.
uint64
sys_uptime(void)
{
  uint xticks;

  acquire(&tickslock);
  xticks = ticks;
  release(&tickslock);
  return xticks;
}

