uint64
sys_wait4(void)
{
  uint64 p;
  int pid;
  if(argint(0, &pid) < 0)
    return -1;
  if(argaddr(1, &p) < 0)
    return -1;
  if (pid == -1){
    int f = wait(p);
    if(p != 0 && f > 0){
      char k = 0x00;
      copyout2(p,(char*)&k,1);
      k = 0x00;
      copyout2(p + 1,(char*)&k,1);
    }
    return f;
  }
  else{
    int f = wait4pid(pid, p);
    if(p != 0 && f > 0){
      char k = 0x00;
      copyout2(p,(char*)&k,1);
      k = 0x03;
      copyout2(p + 1,(char*)&k,1);
    }
    return f;
  }
  //return wait(p);
}

