// Memory allocator by Kernighan and Ritchie,
// The C programming Language, 2nd ed.  Section 8.7.

typedef long Align;

union header {
  struct {
    union header *ptr;
    uint size;
  } s;
  Align x;
};

typedef union header Header;

static Header base;
static Header *freep;

void
free(void *ap)
{
  Header *bp, *p;

  bp = (Header*)ap - 1;
  for(p = freep; !(bp > p && bp < p->s.ptr); p = p->s.ptr)
    if(p >= p->s.ptr && (bp > p || bp < p->s.ptr))
      break;
  if(bp + bp->s.size == p->s.ptr){
    bp->s.size += p->s.ptr->s.size;
    bp->s.ptr = p->s.ptr->s.ptr;
  } else
    bp->s.ptr = p->s.ptr;
  if(p + p->s.size == bp){
    p->s.size += bp->s.size;
    p->s.ptr = bp->s.ptr;
  } else
    p->s.ptr = bp;
  freep = p;
}

static Header*
morecore(uint nu)
{
  char *p;
  Header *hp;

  if(nu < 4096)
    nu = 4096;
  p = sbrk(nu * sizeof(Header));
  if(p == (char*)-1)
    return 0;
  hp = (Header*)p;
  hp->s.size = nu;
  free((void*)(hp + 1));
  return freep;
}

void*
malloc(uint nbytes)
{
  Header *p, *prevp;
  uint nunits;

  nunits = (nbytes + sizeof(Header) - 1)/sizeof(Header) + 1;
  if((prevp = freep) == 0){
    base.s.ptr = freep = prevp = &base;
    base.s.size = 0;
  }
  for(p = prevp->s.ptr; ; prevp = p, p = p->s.ptr){
    if(p->s.size >= nunits){
      if(p->s.size == nunits)
        prevp->s.ptr = p->s.ptr;
      else {
        p->s.size -= nunits;
        p += p->s.size;
        p->s.size = nunits;
      }
      freep = prevp;
      return (void*)(p + 1);
    }
    if(p == freep)
      if((p = morecore(nunits)) == 0)
        return 0;
  }
}

## 内核实现 - 文件系统

#### 用户代码的加载

我们在 `mkfs.c` 中将所有用户标准 shell 程序加载到 `fs.img` 中。在 `link_app.S` 中，我们规定 `fs.img` 的数据全部放在数据段中：

```asm
    .align 4
    .section .data
    .section .data.fs_img
    .global fs_img_start
    .global fs_img_end
fs_img_start:
    .incbin "./fs.img"
fs_img_end:
    .quad 0xffffffff
```

数据段的开头是 `fs_img_start`，结尾是 `fs_img_end`。

#### Ramdisk 读写

最底层的就是磁盘硬件的读和写。对于磁盘的操作，我们可以使用 SD 卡，我们也可以使用内存来模拟磁盘（Ramdisk）。下面介绍 Ramdisk 的相关读写操作：

- 先从 `buf` 数据结构中找到磁盘块的扇区号；
- 根据扇区号找到应该的内存地址；
- 根据 `write` 的值确定是读操作还是写操作。

```c
void 
ramdisk_rw(struct buf *b, int write)
{
  acquire(&ramdisklock);
  uint sectorno = b->sectorno;
  if(b->dev != ROOTDEV)
  	panic("wrong device number");
  lookup_ramdisk_addr(sectorno);
  char *addr = fs_img_start+sectorno*BSIZE;
  if (write)
  {
    memmove((void*)addr, b->data, BSIZE);
  }
  else
  {
    memmove(b->data, (void*)addr, BSIZE);
  }
  release(&ramdisklock);
}
```

## 内核实现 - 时钟中断

####  RISC-V 时钟中断处理：

在我们的系统中，RISC-V 的 CPU 会定期触发一次时钟中断。不同于标准的处理方式，我们采用了一种特殊的方法来处理时钟中断，使其在 M 态而非 S 态下处理。

- **初始化时钟中断**：
  在 `start.c` 中，我们设置所有中断在 S 态下处理。但我们通过 `timerinit()` 为时钟中断创建了专属的处理模式；在这个函数中，我们主要是获取了时钟中断的锁；

- **时钟中断处理逻辑**：当时钟中断发生时，在一般情况下，我们通常将其视为设备中断；在 `devintr()` 中，我们实现了时钟中断的处理逻辑：

  ```c
